/* ============================================
   SHARED STYLES — CSS Hacks & UX Laws

   Design: demo-first, fullscreen-feel
   The page IS the demo. No title. No code block.
   Just the tag chip + the live interactive demo.

   Reference: sorenblank.com/snippets
   ============================================ */

@import url('https://fonts.googleapis.com/css2?family=Space+Mono:ital,wght@0,400;0,500;0,600;0,700;1,400;1,500;1,600;1,700&family=Courier+Prime:ital,wght@0,400;0,700;1,400&display=swap');

/* ============================================
   RESET
   ============================================ */

*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

/* ============================================
   DESIGN TOKENS
   ============================================ */

:root {
  /* palette */
  --bg: #ffffff;
  --surface: rgba(255, 255, 255, 0.72);
  --surface-2: #eef4ef;
  --surface-3: #f2f7f3;
  --border: rgba(22, 51, 37, 0.1);
  --border-light: rgba(22, 51, 37, 0.06);
  --border-strong: rgba(22, 51, 37, 0.18);
  --text: #163325;
  --text-2: rgb(63, 72, 67);
  --text-3: #7a8c81;

  /* accent */
  --mint: #1d7f53;
  --mint-dim: rgba(29, 127, 83, 0.1);
  --mint-bright: #249565;
  --rose: #249565;
  --rose-dim: rgba(29, 127, 83, 0.06);
  --violet: #1d7f53;
  --violet-dim: rgba(29, 127, 83, 0.08);
  --amber: #2d9a6a;
  --sky: #163325;

  /* glow & selection */
  --glow-color: rgba(29, 127, 83, 0.16);
  --selection-bg: rgba(29, 127, 83, 0.16);
  --selection-text: #102217;

  /* structure */
  --radius: 0px;
  --radius-sm: 0px;
  --easing: cubic-bezier(0.645, 0.045, 0.355, 1);
  --ease-out-quart: cubic-bezier(0.165, 0.84, 0.44, 1);
  --transition: all 0.25s cubic-bezier(0.645, 0.045, 0.355, 1);

  /* typography */
  --font-display: 'Space Mono', 'Courier Prime', monospace;
  --font-body: 'Space Mono', 'Courier Prime', monospace;
  --font-mono: 'Space Mono', 'Courier Prime', monospace;

  color-scheme: light;
}

/* ============================================
   BASE — demo pages
   ============================================ */

html,
body {
  height: 100%;
  overflow: hidden;
}

body {
  font-family: var(--font-body);
  font-size: 14px;
  line-height: 1.6;
  background: var(--bg);
  color: var(--text-2);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  scrollbar-width: none;
  -ms-overflow-style: none;
}

::-webkit-scrollbar {
  display: none;
}

::selection {
  background: var(--selection-bg);
  color: var(--selection-text);
}

/* ─── noise overlay ─── */
body::after {
  content: '';
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  z-index: 9999;
  opacity: 0.025;
  background: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.8' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
}

/* ============================================
   DEMO PAGE LAYOUT
   The page is the demo. Centered. Full viewport.
   ============================================ */

main {
  width: 100%;
  max-width: 720px;
  height: 100%;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 40px;
  position: relative;
}

/* ============================================
   TAG CHIP — top-left overlay
   The only identifier on the page
   ============================================ */

.tag {
  position: fixed;
  top: 20px;
  left: 20px;
  z-index: 50;
  display: inline-flex;
  align-items: center;
  font-family: var(--font-mono);
  font-size: 12px;
  font-weight: 400;
  padding: 8px 14px;
  border-radius: 0px;
  letter-spacing: 0.05em;
  text-transform: lowercase;
  background: var(--bg);
  color: var(--text-3);
  border: 1px solid var(--border);
  opacity: 0;
  animation: chipIn 400ms var(--ease-out-quart) 200ms forwards;
  transition: color 0.2s var(--easing), border-color 0.2s var(--easing),
    background 0.2s var(--easing);
  text-decoration: none;
}

.tag:hover {
  color: var(--mint);
  border-color: var(--border-strong);
  background: var(--mint-dim);
}

@keyframes chipIn {
  from {
    opacity: 0;
    transform: translateY(-8px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* back arrow inside the tag on demo pages */
.tag-back-arrow {
  display: inline-block;
  margin-right: 8px;
  transition: transform 0.2s var(--easing);
}

.tag:hover .tag-back-arrow {
  transform: translateX(-3px);
}

/* tag color variants — all collapse to same green */
.tag-mint,
.tag-rose,
.tag-violet {
  /* no color override needed — all same */
}

/* ============================================
   DEMO AREA
   ============================================ */

.demo {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 16px;
  width: 100%;
  flex: 1;
  opacity: 0;
  animation: demoIn 500ms var(--ease-out-quart) 100ms forwards;
}

@keyframes demoIn {
  from {
    opacity: 0;
    transform: translateY(16px) scale(0.98);
  }
  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

/* ============================================
   COMPARISON LAYOUT (side by side)
   ============================================ */

.comparison {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0;
  width: 100%;
  flex: 1;
  align-items: center;
  opacity: 0;
  animation: demoIn 500ms var(--ease-out-quart) 100ms forwards;
}

.side {
  padding: 32px 28px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 16px;
}

.side + .side {
  border-left: 1px solid var(--border);
}

.side-label {
  display: flex;
  align-items: center;
  gap: 7px;
  font-size: 12px;
  font-weight: 400;
  text-transform: lowercase;
  letter-spacing: 0.05em;
  color: var(--text-3);
}

.dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  flex-shrink: 0;
}
.dot-red {
  background: var(--text-3);
}
.dot-green {
  background: var(--mint);
}

/* ============================================
   TOGGLE SWITCH
   ============================================ */

.toggle {
  position: relative;
  display: inline-flex;
  align-items: center;
  gap: 12px;
  cursor: pointer;
  font-size: 13px;
  color: var(--text-2);
  user-select: none;
}

.toggle input {
  position: absolute;
  opacity: 0;
  pointer-events: none;
}

.toggle-track {
  position: relative;
  width: 48px;
  height: 26px;
  background: var(--border-strong);
  border-radius: 999px;
  transition: background 0.25s var(--easing);
  flex-shrink: 0;
}

.toggle-track::after {
  content: '';
  position: absolute;
  top: 3px;
  left: 3px;
  width: 20px;
  height: 20px;
  background: var(--bg);
  border-radius: 50%;
  transition: translate 0.25s var(--easing);
}

.toggle input:checked + .toggle-track {
  background: var(--mint);
}

.toggle input:checked + .toggle-track::after {
  translate: 22px 0;
}

/* ============================================
   SHARED UTILITIES
   ============================================ */

.demo-input {
  width: 100%;
  max-width: 300px;
  padding: 12px 16px;
  border-radius: 0px;
  background: var(--surface-2);
  border: 1px solid var(--border);
  color: var(--text);
  font-family: var(--font-body);
  font-size: 14px;
  outline: none;
  transition: border-color 0.25s var(--easing), box-shadow 0.25s var(--easing);
}

.demo-input:focus {
  border-color: var(--mint);
  box-shadow: 0 0 0 3px var(--mint-dim);
}

/* ============================================
   REDUCED MOTION
   ============================================ */

@media (prefers-reduced-motion: reduce) {
  .tag,
  .demo,
  .comparison {
    animation: none;
    opacity: 1;
  }
}

/* ============================================
   INDEX PAGE STYLES — Video Grid
   ============================================ */

/* ─── grid layout ─── */
.snippet-grid {
  display: grid;
  grid-template-columns: repeat(1, 1fr);
  gap: 8px;
  width: 100%;
  max-width: 2000px;
  margin: 0 auto;
}

@media (min-width: 640px) {
  .snippet-grid {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (min-width: 1024px) {
  .snippet-grid {
    grid-template-columns: repeat(3, 1fr);
  }
}

/* ─── video card ─── */
.snippet-card {
  position: relative;
  display: block;
  overflow: hidden;
  border-radius: 0px;
  aspect-ratio: 16 / 10;
  background: var(--surface-2);
  border: 1px solid var(--border);
  cursor: default;
  text-decoration: none;
}

/* blurred placeholder (LQIP) */
.snippet-card .placeholder {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  filter: blur(32px);
  transform: scale(1.1) translateZ(0);
}

/* autoplay video */
.snippet-card video {
  position: relative;
  width: 100%;
  height: 100%;
  object-fit: cover;
  aspect-ratio: 16 / 10;
  transition: transform 500ms var(--ease-out-quart);
}

@media (prefers-reduced-motion: reduce) {
  .snippet-card video {
    transition: none;
  }
}

/* ─── hover overlay: "view live" button slides up ─── */
.snippet-card .card-overlay {
  position: absolute;
  bottom: 0;
  left: 0;
  width: 100%;
  padding: 6px;
  transform: translateY(100%);
  opacity: 0;
  filter: blur(4px);
  transition: transform 300ms var(--ease-out-quart), opacity 300ms var(--ease-out-quart),
    filter 300ms var(--ease-out-quart);
}

.snippet-card:hover .card-overlay {
  transform: translateY(0);
  opacity: 1;
  filter: blur(0);
}

.card-overlay-inner {
  width: 100%;
  padding: 8px 0;
  text-align: center;
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: 0px;
  cursor: pointer;
}

.card-overlay-inner span {
  font-family: var(--font-mono);
  font-size: 12px;
  font-weight: 500;
  color: var(--text);
  letter-spacing: 0.02em;
}

/* ─── staggered card entrance ─── */
@keyframes cardIn {
  from {
    opacity: 0;
    transform: translateY(20px) scale(0.97);
  }
  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

.snippet-card {
  opacity: 0;
  animation: cardIn 400ms var(--ease-out-quart) both;
}

/* stagger delays: 30ms increments per card */
.snippet-card:nth-child(1) {
  animation-delay: 60ms;
}
.snippet-card:nth-child(2) {
